import SectionHeader from './SectionHeader';

const projects = [
  { num:'01', tag:'Game Modding', tagClass:'bg-amber/10 text-amber2', borderHover:'hover:border-amber/25', dot:'bg-amber', title:'GTA: Vice City — Total Overhaul', desc:'HD textures, redesigned vehicles, revamped sound engine. Shipped with full AR/EN documentation.', chips:['Game Engine','Graphics','Docs'] },
  { num:'02', tag:'Game Modding', tagClass:'bg-teal/10 text-teal2', borderHover:'hover:border-teal/25', dot:'bg-teal', title:'GTA: San Andreas — Next-Gen Mod', desc:'Modernized textures, improved lighting, character control overhaul, and seamless install guide.', chips:['Textures','Lighting','UX'] },
  { num:'03', tag:'Database Systems', tagClass:'bg-lav/20 text-purple-600', borderHover:'hover:border-lav/35', dot:'bg-lav', title:'B.Tech CRM System', desc:'MS Access CRM with relational schema, interactive forms, invoice tracking, and sales reports.', chips:['MS Access','Relational DB','Team ×4'] },
  { num:'04', tag:'Sustainability', tagClass:'bg-coral/10 text-coral', borderHover:'hover:border-coral/25', dot:'bg-coral', title:'HSBC Carbon Neutrality Sim', desc:'Built carbon-neutrality roadmaps and data-driven sustainability recommendations via Forage.', chips:['ESG','Strategy','Forage'] },
];

export default function Projects() {
  return (
    <section id="projects" className="py-24 px-[5%] bg-parchment">
      <SectionHeader tag="Selected Work" title='Featured <em class="italic text-amber not-italic font-serif-display">Projects</em>' />
      <div className="grid md:grid-cols-2 gap-5">
        {projects.map((p, i) => (
          <div key={p.num}
            className={`reveal ${i===1?'delay-1':i===2?'delay-2':i===3?'delay-3':''} relative bg-cream rounded-2xl p-10 border-[1.5px] border-transparent transition-all duration-300 cursor-default flex flex-col ${p.borderHover} hover:-translate-y-1.5 hover:shadow-xl group overflow-hidden`}>
            {/* accent dot */}
            <div className={`absolute w-28 h-28 rounded-full ${p.dot} opacity-[.13] -top-7 -right-7 pointer-events-none`} />
            <div className="absolute top-4 right-5 font-serif-display text-5xl italic text-ink/[.04] leading-none">{p.num}</div>

            <span className={`inline-block text-[.67rem] font-semibold tracking-wider uppercase px-3 py-1 rounded-full mb-4 ${p.tagClass}`}>{p.tag}</span>
            <h3 className="font-serif-display text-xl tracking-tight mb-3 leading-snug">{p.title}</h3>
            <p className="text-[.87rem] leading-[1.75] text-muted2 flex-1">{p.desc}</p>

            <div className="flex items-center justify-between mt-5 pt-4 border-t border-ink/[.07]">
              <div className="flex gap-1.5 flex-wrap">
                {p.chips.map(c => (
                  <span key={c} className="text-[.67rem] font-medium px-2 py-0.5 bg-parchment rounded text-muted">{c}</span>
                ))}
              </div>
              <div className="w-7 h-7 border-[1.5px] border-ink/10 rounded-lg flex items-center justify-center text-muted text-sm transition-all group-hover:border-amber group-hover:text-amber">→</div>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
